function audioId(name=''){const stem=name.replace(/\.[^.]+$/,'');return stem.match(/(?:^|\s-\s)((?:POD[A-Z]*|V?\d{3,}|P\d+))(?:\s-\s|$)/i)?.[1]||stem.match(/^(?:POD[A-Z]*\d+|V?\d{3,}|P\d+)/i)?.[0]||'';}
