function technicalLayout(text=''){const map=new Map();let lesson=0,sequence=0;for(const line of text.split(/\r?\n/)){const h=line.match(/^\s*#{2,4}\s*Lecci[oó]n\s+(\d+)/i);if(h){lesson=Number(h[1]);sequence=0;continue;}if(!lesson||line.trim().startsWith('#'))continue;for(const m of line.matchAll(/(?:^|[^A-Za-z0-9])((?:POD[A-Za-z]*|[A-Za-z]?)[0-9]+)(?![A-Za-z0-9])/gi))if(!map.has(m[1].toLowerCase()))map.set(m[1].toLowerCase(),{lesson,sequence:++sequence});}return map;}
function diagnose(tracks,source={}){const ids=new Set(),duplicates=[];for(const t of tracks){if(ids.has(`${t.type}:${t.id}`))duplicates.push(t.id);ids.add(`${t.type}:${t.id}`);}return {'manifest encontrado':source.manifest?'sí':'no','Audio_Master encontrado':source.audioMaster?'sí':'no','Audios_Tecnico encontrado':source.audioTechnical?'sí':'no','pistas con lesson válido':tracks.filter(t=>t.lesson>0).length,'pistas en Lección 0':tracks.filter(t=>!t.lesson).length,'pistas con text válido':tracks.filter(t=>t.text&&!t.filenameFallback).length,'pistas usando nombre de archivo como fallback':tracks.filter(t=>t.filenameFallback).length,'duplicados por ID':duplicates.length,'archivos sin metadata':tracks.filter(t=>t.filenameFallback).length,'metadata sin archivo':source.metadataWithoutFile||0};}
async function importLocal(fileList){const files=[...fileList],audioFiles=files.filter(f=>f.type.startsWith('audio/')||/\.(mp3|m4a|wav|aac|ogg)$/i.test(f.name));if(!audioFiles.length){$('#status').textContent='El ZIP se seleccionó, pero Safari no permite leerlo sin descomprimir. Selecciona los audios o una carpeta descomprimida.';return;}const manifestFile=findFile(files,'hanstory_manifest.json'),audioCSV=findFile(files,'Audio_Master.csv'),podcastCSV=findFile(files,'Podcast_Master.csv'),audioTechnical=findFile(files,'Audios_Tecnico.txt'),podcastTechnical=findFile(files,'Podcast_Tecnico.txt');let manifest=null;try{if(manifestFile)manifest=JSON.parse(await manifestFile.text());}catch{}const metadataRows=[...parseCSV(audioCSV?await audioCSV.text():''),...parseCSV(podcastCSV?await podcastCSV.text():'')],metadata=new Map(metadataRows.map(r=>[(r.id||r.audio_id||'').toLowerCase(),r])),layout=new Map([...(technicalLayout(podcastTechnical?await podcastTechnical.text():'')).entries(),...(technicalLayout(audioTechnical?await audioTechnical.text():'')).entries()]);const chosen=new Map();for(const f of audioFiles){const id=audioId(f.name);if(!id)continue;const key=`${/podcast/i.test(pathOf(f))||/^pod/i.test(id)?'podcast':'phrase'}:${id.toLowerCase()}`,candidate={f,...fileLayout(pathOf(f))};const old=chosen.get(key);if(!old||(candidate.lesson&&!old.lesson))chosen.set(key,candidate);}let tracks=[];if(manifest?.tracks?.length){for(const source of manifest.tracks){const match=[...chosen.values()].find(x=>audioId(x.f.name).toLowerCase()===String(source.id).toLowerCase());if(match)tracks.push({...source,audio_path:URL.createObjectURL(match.f),local:true,filenameFallback:false});}}else{tracks=[...chosen.values()].map(({f,lesson,sequence},i)=>{const id=audioId(f.name),m=metadata.get(id.toLowerCase())||{},tech=layout.get(id.toLowerCase())||{};return {id,lesson:tech.lesson||lesson||Number(m.lesson||m.lesson_number||0),sequence:tech.sequence||sequence||i+1,speaker:m.speaker_or_blank||m.speaker||f.name.split(' - ')[2]||'',text:m.text||f.name.replace(/\.[^.]+$/,'').split(' - ').slice(3).join(' - ')||f.name,translation:m.translation_or_blank||m.translation||'',audio_path:URL.createObjectURL(f),type:/podcast/i.test(pathOf(f))||/^pod/i.test(id)?'podcast':(m.type||'phrase'),section:m.section||'',local:true,filenameFallback:!m.text};});}tracks.sort(trackSort);const lessonNumbers=[...new Set(tracks.map(t=>t.lesson))].sort((a,b)=>(a||999999)-(b||999999)),code=manifest?.project_code||`LOCAL-${Date.now()}`,sourceFiles={manifest:!!manifestFile,audioMaster:!!audioCSV,audioTechnical:!!audioTechnical,metadataWithoutFile:metadataRows.filter(r=>!tracks.some(t=>String(t.id).toLowerCase()===String(r.id).toLowerCase())).length},diagnostics=diagnose(tracks,sourceFiles);await put('localBooks',{id:code,code,title:manifest?.title||audioFiles[0].webkitRelativePath?.split('/')[0]||'Libro local',target_language:manifest?.target_language||'',type:'Libro privado',tracks,sourceFiles,diagnostics,createdAt:new Date().toISOString()});state.tab='local';document.querySelectorAll('.tab').forEach(x=>x.classList.toggle('active',x.dataset.library==='local'));renderBooks();$('#status').textContent=`Importadas ${tracks.length} pistas lógicas en ${lessonNumbers.length} lecciones. Se eliminaron copias duplicadas por ID y modo.`;}
async function importLocalWithExplanations(files){await importLocal(files);const explanationFile=findFile([...files],'track_explanations.json');if(!explanationFile)return;try{const payload=JSON.parse(await explanationFile.text()),books=(await all('localBooks')).sort((a,b)=>String(b.createdAt).localeCompare(String(a.createdAt)));if(books[0]){books[0].explanations=payload.items||{};await put('localBooks',books[0]);}}catch{$('#status').textContent+=' El archivo de explicaciones no pudo interpretarse.';}}
$('#import-files').onchange=e=>importLocalWithExplanations(e.target.files);$('#import-folder').onchange=e=>importLocalWithExplanations(e.target.files);
